export function calculateParkingFee(
  durationMinutes: number,
  isWeekend: boolean,
  isElectric: boolean,
  isLostTicket: boolean
): number {
  if (isLostTicket) {
    return 45.0;
  }

  if (durationMinutes <= 15) {
    return 0.0;
  }

  const hours = Math.ceil(durationMinutes / 60);
  let fee = hours * 3.5;

  if (isElectric) {
    fee = fee * 0.8;
    fee = Math.round(fee * 4) / 4;
  }

  const dailyCap = isWeekend ? 18.0 : 24.0;
  fee = Math.min(fee, dailyCap);

  return Math.round(fee * 100) / 100;
}

function calculateParkingFee(
  minutes: number,
  vehicleType: string,
  isWeekend: boolean,
  lostTicket: boolean
): number {
  if (lostTicket) return 45.0;

  if (minutes <= 15) return 0.0;

  const hours = Math.ceil(minutes / 60);
  let fee = hours * 3.5;

  if (vehicleType === "electric") {
    fee *= 0.8;
    fee = Math.round(fee * 4) / 4;
  }

  const dailyMax = isWeekend ? 18 : 24;
  fee = Math.min(fee, dailyMax);

  return Math.round(fee * 100) / 100;
}

function calculateParkingFee(
  duration: number,
  vehicleType: string,
  dayType: string,
  ticketStatus: string
): number {
  if (ticketStatus === "lost") {
    return 45.0;
  }

  // First 15 minutes are free
  if (duration <= 15) {
    return 0.0;
  }

  // Round up to nearest hour
  const minutesCharged = duration - 15;
  const hoursRounded = Math.ceil(minutesCharged / 60);

  // Calculate base fee: $3.50 per hour
  let fee = hoursRounded * 3.5;

  // Apply EV discount (20%)
  if (vehicleType === "electric") {
    fee = fee * 0.8;
    // Round to nearest quarter dollar
    fee = Math.round(fee * 4) / 4;
  }

  // Apply daily maximum based on day type
  const dailyMax = dayType === "weekend" ? 18 : 24;
  fee = Math.min(fee, dailyMax);

  // Round to nearest cent
  return Math.round(fee * 100) / 100;
}

function calculateParkingFee(
  durationMinutes: number,
  isElectricVehicle: boolean,
  isLostTicket: boolean,
  dayOfWeek: number
): number {
  if (isLostTicket) {
    return 45.0;
  }

  const FREE_MINUTES = 15;
  const HOURLY_RATE = 3.5;
  const EV_DISCOUNT = 0.2;
  const QUARTER = 0.25;

  const chargeableMinutes = Math.max(0, durationMinutes - FREE_MINUTES);
  const hoursRoundedUp = Math.ceil(chargeableMinutes / 60);
  let fee = hoursRoundedUp * HOURLY_RATE;

  if (isElectricVehicle) {
    fee = fee * (1 - EV_DISCOUNT);
  }

  fee = Math.round(fee / QUARTER) * QUARTER;

  const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
  const dailyMax = isWeekend ? 18 : 24;
  fee = Math.min(fee, dailyMax);

  return Math.round(fee * 100) / 100;
}

export { calculateParkingFee };

function calculateParkingFee(
  entryTime: Date,
  exitTime: Date,
  vehicleType: 'standard' | 'electric',
  isLostTicket: boolean
): number {
  if (isLostTicket) {
    return 45.0;
  }

  const durationMs = exitTime.getTime() - entryTime.getTime();
  const durationMinutes = durationMs / (1000 * 60);

  if (durationMinutes <= 15) {
    return 0;
  }

  const chargeableMinutes = durationMinutes - 15;
  const chargeableHours = Math.ceil(chargeableMinutes / 60);
  let fee = chargeableHours * 3.5;

  if (vehicleType === 'electric') {
    fee *= 0.8;
  }

  const feeInQuarters = Math.round(fee * 4) / 4;

  const dayOfWeek = exitTime.getDay();
  const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
  const dailyCap = isWeekend ? 18 : 24;

  const cappedFee = Math.min(feeInQuarters, dailyCap);
  return Math.round(cappedFee * 100) / 100;
}

