main();

function calculateParkingFee(
  entryTime: Date,
  exitTime: Date,
  vehicleType: 'regular' | 'electric',
  dayOfWeek: number,
  lostTicket: boolean
): number {
  if (lostTicket) return 45.0;

  const stayMs = exitTime.getTime() - entryTime.getTime();
  const stayMinutes = stayMs / 60000;

  const billableMinutes = Math.max(0, stayMinutes - 15);
  const hours = Math.ceil(billableMinutes / 60);

  let hourlyRate = 3.5;
  if (vehicleType === 'electric') {
    hourlyRate *= 0.8;
  }

  let fee = hours * hourlyRate;

  fee = Math.round(fee * 4) / 4;

  const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
  const cap = isWeekend ? 18 : 24;
  fee = Math.min(fee, cap);

  return Math.round(fee * 100) / 100;
}

import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

async function calculateParkingFee(
  durationMinutes: number,
  vehicleType: "standard" | "electric",
  isLostTicket: boolean,
  dayOfWeek: number
): Promise<number> {
  const message = await client.messages.create({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 1024,
    messages: [
      {
        role: "user",
        content: `Calculate parking fee with these rules:
1. If lost ticket: return $45 flat fee
2. Grace period: 15 minutes (subtract from duration)
3. Round billable minutes UP to nearest hour
4. Hourly rate: $3.50 standard, $2.80 electric
5. Round to nearest quarter-dollar
6. Daily cap: $24 weekdays (0-4), $18 weekends (5-6)
7. Final round to nearest cent

Input:
- Duration: ${durationMinutes} minutes
- Vehicle: ${vehicleType}
- Lost ticket: ${isLostTicket}
- Day of week: ${dayOfWeek} (0=Sun, 6=Sat)

Return ONLY the numeric fee value (e.g., 12.50).`,
      },
    ],
  });

  const responseText =
    message.content[0].type === "text" ? message.content[0].text : "";
  const fee = parseFloat(responseText.trim());

  // Verify with local calculation
  if (isLostTicket) {
    return 45.0;
  }

  const billableMinutes = Math.max(0, durationMinutes - 15);
  const billableHours = Math.ceil(billableMinutes / 60);
  const hourlyRate = vehicleType === "electric" ? 2.8 : 3.5;
  let baseFee = billableHours * hourlyRate;

  baseFee = Math.round(baseFee * 4) / 4;

  const dailyCap = dayOfWeek === 0 || dayOfWeek === 6 ? 18 : 24;
  const cappedFee = Math.min(baseFee, dailyCap);

  return Math.round(cappedFee * 100) / 100;
}

async function main() {
  const testCases = [
    { duration: 30, vehicle: "standard" as const, lost: false, day: 1 },
    { duration: 120, vehicle: "electric" as const, lost: false, day: 3 },
    { duration: 60, vehicle: "standard" as const, lost: true, day: 5 },
    { duration: 480, vehicle: "standard" as const, lost: false, day: 6 },
  ];

  for (const test of testCases) {
    const fee = await calculateParkingFee(
      test.duration,
      test.vehicle,
      test.lost,
      test.day
    );
    console.log(
      `Duration: ${test.duration}min, Vehicle: ${test.vehicle}, Lost: ${test.lost}, Day: ${test.day} => $${fee.toFixed(2)}`
    );
  }
}

main().catch(console.error);
